=<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>User Narrative</title>
    <!-- Premium Serif and Sans-Serif Fonts -->
    <link href="https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,600;1,400&family=Montserrat:wght@300;400&display=swap" rel="stylesheet">
    <style>
        :root {
            --bg-color: #fdfbf7; /* Soft paper tint */
            --text-main: #1a1a1a;
            --text-secondary: #5e5e5e;
            --border-color: #d1d1d1;
            --accent-color: #8c7851; /* Muted gold/bronze */
        }

        body {
            margin: 0;
            padding: 0;
            background-color: var(--bg-color);
            color: var(--text-main);
            font-family: 'Cormorant Garamond', serif;
            display: flex;
            justify-content: center;
            min-height: 100vh;
        }

        .main-container {
            max-width: 800px;
            width: 90%;
            margin: 80px 0;
            padding: 60px;
            border: 1px solid var(--border-color);
            position: relative;
        }

        /* The thin frame effect */
        .main-container::before {
            content: "";
            position: absolute;
            top: 10px;
            left: 10px;
            right: 10px;
            bottom: 10px;
            border: 1px solid var(--border-color);
            pointer-events: none;
        }

        header {
            text-align: center;
            margin-bottom: 60px;
            position: relative;
        }

        .pre-title {
            font-family: 'Montserrat', sans-serif;
            text-transform: uppercase;
            letter-spacing: 5px;
            font-size: 0.7rem;
            color: var(--accent-color);
            display: block;
            margin-bottom: 15px;
        }

        .greeting {
            font-size: clamp(2.5rem, 5vw, 4rem);
            font-weight: 300;
            margin: 0;
            line-height: 1.1;
            font-style: italic;
        }

        .divider {
            width: 60px;
            height: 1px;
            background: var(--accent-color);
            margin: 40px auto;
        }

        .story-content {
            font-size: 1.4rem;
            line-height: 1.8;
            color: var(--text-main);
            text-align: justify;
            max-width: 600px;
            margin: 0 auto;
            /* Respects paragraphs and spacing from backend */
            white-space: pre-wrap;
        }

        /* Elegant Drop Cap */
        .story-content::first-letter {
            float: left;
            font-size: 4.5rem;
            line-height: 1;
            padding-right: 15px;
            padding-top: 5px;
            font-weight: 600;
            color: var(--text-main);
        }

        footer {
            margin-top: 60px;
            text-align: center;
            font-family: 'Montserrat', sans-serif;
            font-size: 0.65rem;
            letter-spacing: 3px;
            text-transform: uppercase;
            color: var(--text-secondary);
        }

        @media (max-width: 600px) {
            .main-container {
                padding: 30px 20px;
                margin: 20px 0;
            }
            .story-content {
                font-size: 1.2rem;
                text-align: left;
            }
        }
    </style>
</head>
<body>

    <main class="main-container">
        <header>
            <span class="pre-title">A Personal Account</span>
            <!-- Backend Variable: name -->
            <h1 class="greeting">Welcome, {{ $('Webhook').item.json.query.FirstName }}</h1>
            <div class="divider"></div>
        </header>

        <article>
            <!-- Backend Variable: story -->
            <div class="story-content">
{{ $json.output.content }}
            </div>
        </article>

        <footer>
            MCMXXIV &bull; Private Collection
        </footer>
    </main>

</body>
</html>

